from skimage.metrics import structural_similarityimport cv2# Works well with images of different dimensionsdef orb_sim(img1, img2):    # ORB detects keypoints and descriptors    orb = cv2.ORB_create()    kp_a, desc_a = orb.detectAndCompute(img1, None)    kp_b, desc_b = orb.detectAndCompute(img2, None)    # If no descriptors are found, return 0    if desc_a is None or desc_b is None:        return 0    # Brute-force matcher for ORB descriptors    bf = cv2.BFMatcher(cv2.NORM_HAMMING, crossCheck=True)    # Match descriptors between two images    matches = bf.match(desc_a, desc_b)    if len(matches) == 0:        return 0    # Smaller distance means more similar    similar_regions = [m for m in matches if m.distance < 50]    return len(similar_regions) / len(matches)# Needs images to be the same dimensionsdef structural_sim(img1, img2):    sim, diff = structural_similarity(img1, img2, full=True)    return simimg00 = cv2.imread("..data/monkey_distorted.jpg", 0)img01 = cv2.imread("..data/monkey_rotated.jpg", 0)orb_similarity = orb_sim(img00, img01)print("ORB similarity:", orb_similarity)from skimage.transform import resizessim = structural_sim(img00,img01)print("Structural Similarity using SSIM is:", ssim)